void ff_h263_pred_acdc ( MpegEncContext * s , int16_t * block , int n ) {
 int x , y , wrap , a , c , pred_dc , scale , i ;
 int16_t * dc_val , * ac_val , * ac_val1 ;
 if ( n < 4 ) {
 x = 2 * s -> mb_x + ( n & 1 ) ;
 y = 2 * s -> mb_y + ( n >> 1 ) ;
 wrap = s -> b8_stride ;
 dc_val = s -> dc_val [ 0 ] ;
 ac_val = s -> ac_val [ 0 ] [ 0 ] ;
