static uint16_t * appendEncodedByte ( uint16_t * buffer , uint16_t * buffLimit , uint8_t value , uint8_t state [ ] , UErrorCode * status ) {
 if ( ! status || U_FAILURE ( * status ) ) {
 return NULL ;
