 break ;
 case TS_IPV6_ADDR_RANGE : if ( object . len > 17 ) {
 DBG1 ( DBG_ASN , "IPv6 address object is larger than 17 octets" ) ;
 return FALSE ;
 }
 break ;
 default : DBG1 ( DBG_ASN , "unknown address family" ) ;
 return FALSE ;
