 limit = UINT64_MAX / base ;
 last_digit_limit = UINT64_MAX % base ;
 while ( ( * p == ' ' || * p == '\t' ) && char_cnt -- > 0 ) p ++ ;
 l = 0 ;
 digit = * p - '0' ;
 while ( * p >= '0' && digit < base && char_cnt -- > 0 ) {
 if ( l > limit || ( l == limit && digit > last_digit_limit ) ) {
 l = UINT64_MAX ;
