 intr . irq = irq ;
 DPRINTF ( "injected interrupt %d\n" , irq ) ;
 ret = kvm_vcpu_ioctl ( cpu , KVM_INTERRUPT , & intr ) ;
 if ( ret < 0 ) {
 fprintf ( stderr , "KVM: injection failed, interrupt lost (%s)\n" , strerror ( - ret ) ) ;
