 src = & opp -> src [ n_IRQ ] ;
 DPRINTF ( "openpic: set irq %d = %d ivpr=0x%08x\n" , n_IRQ , level , src -> ivpr ) ;
 if ( src -> level ) {
 src -> pending = level ;
 openpic_update_irq ( opp , n_IRQ ) ;
 }
 else {
 if ( level ) {
 src -> pending = 1 ;
 openpic_update_irq ( opp , n_IRQ ) ;
 }
 if ( src -> output != OPENPIC_OUTPUT_INT ) {
