 if ( left ) memset ( dst , ref_row [ 0 ] , left ) ;
 if ( copy ) memcpy ( dst + left , ref_row + x + left , copy ) ;
 if ( right ) memset ( dst + left + copy , ref_row [ w - 1 ] , right ) ;
 dst += dst_stride ;
 ++ y ;
 if ( y > 0 && y < h ) ref_row += src_stride ;
 }
 while ( -- b_h ) ;
