 dst += 2 ;
 case 8 : case 2 : TOHEX ( dst , ( address >> 16 ) , check_sum ) ;
 dst += 2 ;
 case 9 : case 1 : case 0 : TOHEX ( dst , ( address >> 8 ) , check_sum ) ;
 dst += 2 ;
