 socklen = pfkey_sockaddr_len ( family ) ;
 if ( pfkey_sockaddr_extract ( ( struct sockaddr * ) ( sa + socklen ) , & t -> id . daddr ) != family ) return - EINVAL ;
 t -> encap_family = family ;
 }
 else t -> encap_family = xp -> family ;
 t -> allalgs = 1 ;
 xp -> xfrm_nr ++ ;
